     1|/**
     2| * IVX Soft-Delete Module — never hard-delete production data.
     3| *
     4| * Instead of DELETE, every protected table row is marked with:
     5| *   deleted_at   ISO timestamp of deletion
     6| *   deleted_by   user id / system id that performed the delete
     7| *   delete_reason  written reason (required)
     8| *
     9| * Soft-deleted rows are hidden from normal UI queries (filters that
    10| * exclude deleted_at IS NOT NULL) but remain in the table and can be
    11| * restored by the owner at any time via the Restore Center.
    12| *
    13| * @module ivx-soft-delete
    14| */
    15|
    16|export const IVX_SOFT_DELETE_MARKER = 'ivx-soft-delete-2026-07-06';
    17|
    18|type SupabaseConfig = { url: string; key: string; missing: string[] };
    19|
    20|function resolveSupabase(): SupabaseConfig {
    21|  const url = (process.env.EXPO_PUBLIC_SUPABASE_URL || process.env.SUPABASE_URL || '').trim().replace(/\/+$/, '');
    22|  const key = (process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_SERVICE_KEY || '').trim();
    23|  const missing: string[] = [];
    24|  if (!url) missing.push('EXPO_PUBLIC_SUPABASE_URL');
    25|  if (!key) missing.push('SUPABASE_SERVICE_ROLE_KEY');
    26|  return { url, key, missing };
    27|}
