    29|export type SoftDeleteRequest = {
    30|  table: string;
    31|  recordId: string | number;
    32|  deletedBy: string;
    33|  reason: string;
    34|  /** Column name used as the primary key. Defaults to "id". */
    35|  pkColumn?: string;
    36|};
    37|
    38|export type SoftDeleteResult = {
    39|  ok: boolean;
    40|  table: string;
    41|  recordId: string | number;
    42|  status: number;
    43|  error: string | null;
    44|  timestamp: string;
    45|};
    46|
    47|const SAFE_TABLE_RE = /^[a-z_][a-z0-9_]*$/;
    48|const SAFE_PK_RE = /^[a-z_][a-z0-9_]*$/;
    49|
    50|/**
    51| * Soft-delete a single row by setting deleted_at/deleted_by/delete_reason.
    52| * The row is NOT removed from the table — it is only marked deleted.
    53| */
    54|export async function softDeleteRow(req: SoftDeleteRequest): Promise<SoftDeleteResult> {
    55|  const timestamp = new Date().toISOString();
    56|  const table = req.table.toLowerCase();
    57|  const pk = (req.pkColumn ?? 'id').toLowerCase();
    58|
    59|  if (!SAFE_TABLE_RE.test(table)) {
    60|    return { ok: false, table: req.table, recordId: req.recordId, status: 400, error: 'invalid_table_name', timestamp };
    61|  }
    62|  if (!SAFE_PK_RE.test(pk)) {
    63|    return { ok: false, table, recordId: req.recordId, status: 400, error: 'invalid_pk_column', timestamp };
    64|  }
    65|  if (!req.reason.trim()) {
    66|    return { ok: false, table, recordId: req.recordId, status: 400, error: 'reason_required', timestamp };
    67|  }
    68|
    69|  const supa = resolveSupabase();
    70|  if (supa.missing.length > 0) {
    71|    return { ok: false, table, recordId: req.recordId, status: 500, error: `not_configured: ${supa.missing.join(', ')}`, timestamp };
    72|  }
    73|
    74|  try {
    75|    const res = await fetch(`${supa.url}/rest/v1/${table}?${pk}=eq.${encodeURIComponent(String(req.recordId))}`, {
    76|      method: 'PATCH',
    77|      headers: {
    78|        apikey: supa.key,
    79|        Authorization: `Bearer ${supa.key}`,
    80|        'Content-Type': 'application/json',
    81|        Prefer: 'return=representation',
    82|      },
    83|      body: JSON.stringify({
    84|        deleted_at: timestamp,
    85|        deleted_by: req.deletedBy,
    86|        delete_reason: req.reason.slice(0, 1000),
    87|      }),
    88|    });
    89|
    90|    if (!res.ok) {
    91|      const body = await res.text().catch(() => '');
    92|      return { ok: false, table, recordId: req.recordId, status: res.status, error: `HTTP_${res.status}: ${body.slice(0, 200)}`, timestamp };
    93|    }
    94|
    95|    return { ok: true, table, recordId: req.recordId, status: 200, error: null, timestamp };
    96|  } catch (err) {
    97|    return { ok: false, table, recordId: req.recordId, status: 0, error: err instanceof Error ? err.message : 'network_error', timestamp };
    98|  }
