     1|/**
     2| * IVX Supabase data_vault table — captures every pre-mutation record to a
     3| * dedicated Supabase table BEFORE any UPDATE/DELETE touches it, so the owner
     4| * can restore individual records from inside Supabase itself (not only from
     5| * the file-based vault).
     6| *
     7| * Schema (created via ensureDataVaultTable):
     8| *   CREATE TABLE IF NOT EXISTS public.data_vault (
     9| *     id BIGSERIAL PRIMARY KEY,
    10| *     vault_id TEXT NOT NULL,
    11| *     table_name TEXT NOT NULL,
    12| *     record_id TEXT,
    13| *     action TEXT NOT NULL,            -- 'UPDATE' | 'DELETE' | 'TRUNCATE'
    14| *     old_data JSONB,
    15| *     new_data JSONB,
    16| *     user_id TEXT,
    17| *     reason TEXT,
    18| *     hash TEXT,
    19| *     created_at TIMESTAMPTZ NOT NULL DEFAULT now()
    20| *   );
    21| *
    22| * @module ivx-vault-table
    23| */
    24|
    25|import { createHash } from 'node:crypto';
    26|
    27|export const IVX_VAULT_TABLE_MARKER = 'ivx-vault-table-2026-07-06';
    28|
    29|type SupabaseConfig = { url: string; key: string; missing: string[] };
    30|
    31|function resolveSupabase(): SupabaseConfig {
    32|  const url = (process.env.EXPO_PUBLIC_SUPABASE_URL || process.env.SUPABASE_URL || '').trim().replace(/\/+$/, '');
    33|  const key = (process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_SERVICE_KEY || '').trim();
    34|  const missing: string[] = [];
    35|  if (!url) missing.push('EXPO_PUBLIC_SUPABASE_URL');
    36|  if (!key) missing.push('SUPABASE_SERVICE_ROLE_KEY');
    37|  return { url, key, missing };
    38|}
