    40|const SAFE_TABLE_RE = /^[a-z_][a-z0-9_]*$/;
    41|
    42|export type VaultCaptureInput = {
    43|  table: string;
    44|  recordId: string | number | null;
    45|  action: 'UPDATE' | 'DELETE' | 'TRUNCATE';
    46|  oldData: Record<string, unknown> | null;
    47|  newData?: Record<string, unknown> | null;
    48|  userId: string;
    49|  reason: string;
    50|};
    51|
    52|export type VaultCaptureResult = {
    53|  ok: boolean;
    54|  vaultId: string;
    55|  status: number;
    56|  error: string | null;
    57|};
    58|
    59|function makeVaultId(): string {
    60|  return `vault-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
    61|}
    62|
    63|function hashVaultEntry(input: VaultCaptureInput): string {
    64|  return createHash('sha256')
    65|    .update(JSON.stringify({
    66|      table: input.table,
    67|      recordId: input.recordId,
    68|      action: input.action,
    69|      oldData: input.oldData,
    70|      newData: input.newData ?? null,
    71|      ts: Date.now(),
    72|    }))
    73|    .digest('hex');
    74|}
