    76|/**
    77| * Capture a record into the data_vault Supabase table. This should be called
    78| * BEFORE any destructive or mutating operation on protected tables.
    79| */
    80|export async function captureToVault(input: VaultCaptureInput): Promise<VaultCaptureResult> {
    81|  const vaultId = makeVaultId();
    82|  const table = input.table.toLowerCase();
    83|  if (!SAFE_TABLE_RE.test(table)) {
    84|    return { ok: false, vaultId, status: 400, error: 'invalid_table_name' };
    85|  }
    86|  if (!input.reason.trim()) {
    87|    return { ok: false, vaultId, status: 400, error: 'reason_required' };
    88|  }
    89|
    90|  const supa = resolveSupabase();
    91|  if (supa.missing.length > 0) {
    92|    return { ok: false, vaultId, status: 500, error: `not_configured: ${supa.missing.join(', ')}` };
    93|  }
    94|
    95|  const hash = hashVaultEntry(input);
    96|
    97|  try {
    98|    const res = await fetch(`${supa.url}/rest/v1/data_vault`, {
    99|      method: 'POST',
   100|      headers: {
   101|        apikey: supa.key,
   102|        Authorization: `Bearer ${supa.key}`,
   103|        'Content-Type': 'application/json',
   104|        Prefer: 'return=representation',
   105|      },
   106|      body: JSON.stringify({
   107|        vault_id: vaultId,
   108|        table_name: table,
   109|        record_id: input.recordId === null ? null : String(input.recordId),
   110|        action: input.action,
   111|        old_data: input.oldData,
   112|        new_data: input.newData ?? null,
   113|        user_id: input.userId,
   114|        reason: input.reason.slice(0, 1000),
   115|        hash,
   116|      }),
   117|    });
   118|
   119|    if (!res.ok) {
   120|      const body = await res.text().catch(() => '');
   121|      return { ok: false, vaultId, status: res.status, error: `HTTP_${res.status}: ${body.slice(0, 200)}` };
   122|    }
   123|    return { ok: true, vaultId, status: 201, error: null };
   124|  } catch (err) {
   125|    return { ok: false, vaultId, status: 0, error: err instanceof Error ? err.message : 'network_error' };
   126|  }
