   151|/**
   152| * List data_vault entries, optionally filtered by table.
   153| */
   154|export async function listVaultEntries(opts: { table?: string; limit?: number } = {}): Promise<VaultListResult> {
   155|  const supa = resolveSupabase();
   156|  if (supa.missing.length > 0) {
   157|    return { ok: false, entries: [], count: 0, status: 500, error: `not_configured: ${supa.missing.join(', ')}` };
   158|  }
   159|  const limit = Math.max(1, Math.min(500, opts.limit ?? 100));
   160|  let query = `${supa.url}/rest/v1/data_vault?order=created_at.desc&limit=${limit}`;
   161|  if (opts.table) {
   162|    const t = opts.table.toLowerCase();
   163|    if (!SAFE_TABLE_RE.test(t)) {
   164|      return { ok: false, entries: [], count: 0, status: 400, error: 'invalid_table_name' };
   165|    }
   166|    query += `&table_name=eq.${encodeURIComponent(t)}`;
   167|  }
   168|
   169|  try {
   170|    const res = await fetch(query, {
   171|      headers: { apikey: supa.key, Authorization: `Bearer ${supa.key}`, Accept: 'application/json' },
   172|    });
   173|    if (res.status === 404) return { ok: false, entries: [], count: 0, status: 404, error: 'data_vault_table_not_found' };
   174|    if (!res.ok) return { ok: false, entries: [], count: 0, status: res.status, error: `HTTP_${res.status}` };
   175|    const rows = (await res.json()) as VaultEntry[];
   176|    return { ok: true, entries: rows, count: rows.length, status: 200, error: null };
   177|  } catch (err) {
   178|    return { ok: false, entries: [], count: 0, status: 0, error: err instanceof Error ? err.message : 'network_error' };
   179|  }
