   182|/**
   183| * Restore a single record from a vault entry back into its original table.
   184| * Uses upsert (merge-duplicates) so the PK row is restored to its old_data state.
   185| */
   186|export async function restoreFromVault(vaultId: string): Promise<{ ok: boolean; status: number; error: string | null; restoredTable: string | null; recordId: string | null }> {
   187|  const supa = resolveSupabase();
   188|  if (supa.missing.length > 0) {
   189|    return { ok: false, status: 500, error: `not_configured: ${supa.missing.join(', ')}`, restoredTable: null, recordId: null };
   190|  }
   191|
   192|  try {
   193|    const fetchRes = await fetch(
   194|      `${supa.url}/rest/v1/data_vault?vault_id=eq.${encodeURIComponent(vaultId)}&limit=1`,
   195|      { headers: { apikey: supa.key, Authorization: `Bearer ${supa.key}`, Accept: 'application/json' } },
   196|    );
   197|    if (!resOk(fetchRes)) return { ok: false, status: fetchRes.status, error: `fetch_failed_${fetchRes.status}`, restoredTable: null, recordId: null };
   198|    const entries = (await fetchRes.json()) as VaultEntry[];
   199|    if (entries.length === 0) return { ok: false, status: 404, error: 'vault_entry_not_found', restoredTable: null, recordId: null };
   200|    const entry = entries[0];
   201|    if (!entry.old_data) return { ok: false, status: 409, error: 'no_old_data_to_restore', restoredTable: entry.table_name, recordId: entry.record_id };
   202|
   203|    const restoreRes = await fetch(`${supa.url}/rest/v1/${entry.table_name}`, {
   204|      method: 'POST',
   205|      headers: {
   206|        apikey: supa.key,
   207|        Authorization: `Bearer ${supa.key}`,
   208|        'Content-Type': 'application/json',
   209|        Prefer: 'return=minimal,resolution=merge-duplicates',
   210|      },
   211|      body: JSON.stringify([entry.old_data]),
   212|    });
   213|    if (!resOk(restoreRes)) {
   214|      const body = await restoreRes.text().catch(() => '');
   215|      return { ok: false, status: restoreRes.status, error: `HTTP_${restoreRes.status}: ${body.slice(0, 200)}`, restoredTable: entry.table_name, recordId: entry.record_id };
   216|    }
   217|    return { ok: true, status: 200, error: null, restoredTable: entry.table_name, recordId: entry.record_id };
   218|  } catch (err) {
   219|    return { ok: false, status: 0, error: err instanceof Error ? err.message : 'network_error', restoredTable: null, recordId: null };
   220|  }
   221|}
   222|
   223|function resOk(r: Response): boolean {
   224|  return r.status >= 200 && r.status < 300;
   225|}

