     1|/**
     2| * IVX PITR (Point-in-Time Recovery) status check.
     3| *
     4| * Probes Supabase for backup/PITR availability by checking:
     5| *   1. Whether the project responds to the management/health endpoints.
     6| *   2. The age of the newest row across critical tables (proxy for "last
     7| *      write" — gives the owner a concrete "data is fresh as of X" signal).
     8| *   3. Whether the file-based Data Vault has recent snapshots (our own
     9| *      independent backup layer).
    10| *
    11| * Supabase's PITR config itself is only visible in the Supabase Dashboard
    12| * (it requires the platform API + project ref + a service key with platform
    13| * scope, which is not the same as the database service role key). So we
    14| * surface what we CAN verify from the backend and clearly flag that PITR
    15| * enablement must be confirmed in the Dashboard.
    16| *
    17| * @module ivx-pitr-status
    18| */
    19|
    20|export const IVX_PITR_MARKER = 'ivx-pitr-status-2026-07-06';
    21|
    22|type SupabaseConfig = { url: string; key: string; missing: string[] };
    23|
    24|function resolveSupabase(): SupabaseConfig {
    25|  const url = (process.env.EXPO_PUBLIC_SUPABASE_URL || process.env.SUPABASE_URL || '').trim().replace(/\/+$/, '');
    26|  const key = (process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_SERVICE_KEY || '').trim();
    27|  const missing: string[] = [];
    28|  if (!url) missing.push('EXPO_PUBLIC_SUPABASE_URL');
    29|  if (!key) missing.push('SUPABASE_SERVICE_ROLE_KEY');
    30|  return { url, key, missing };
    31|}
