    62|/**
    63| * Probe Supabase for PITR / backup status. Returns a honest report the owner
    64| * can act on. Does not fabricate PITR availability — it clearly states when
    65| * PITR status must be confirmed in the Dashboard.
    66| */
    67|export async function checkPitrStatus(fileVaultSnapshotCount?: number, fileVaultLastSnapshotAt?: string | null): Promise<PitrStatus> {
    68|  const checkedAt = new Date().toISOString();
    69|  const supa = resolveSupabase();
    70|
    71|  if (supa.missing.length > 0) {
    72|    return {
    73|      marker: IVX_PITR_MARKER,
    74|      checkedAt,
    75|      supabaseUrl: null,
    76|      supabaseReachable: false,
    77|      pitrDashboardConfirmed: null,
    78|      pitrAlert: `Supabase not configured: ${supa.missing.join(', ')}`,
    79|      restoreWindowNote: 'Unavailable — Supabase not configured.',
    80|      criticalTables: [],
    81|      newestWriteAt: null,
    82|      oldestWriteAt: null,
    83|      fileVaultSnapshots: fileVaultSnapshotCount ?? null,
    84|      fileVaultLastSnapshotAt: fileVaultLastSnapshotAt ?? null,
    85|      recommendation: 'Configure Supabase credentials before PITR status can be checked.',
    86|    };
    87|  }
    88|
    89|  const headers = { apikey: supa.key, Authorization: `Bearer ${supa.key}`, Accept: 'application/json' };
