    21|
    22|export const IVX_TWO_PERSON_MARKER = 'ivx-two-person-approval-2026-07-06';
    23|
    24|const APPROVALS_FILE = path.resolve(process.cwd(), 'logs', 'audit', 'data-vault', 'two-person-approvals.jsonl');
    25|
    26|export type DestructiveApprovalRequest = {
    27|  operation: 'DELETE' | 'TRUNCATE' | 'DROP';
    28|  tables: string[];
    29|  reason: string;
    30|  typedConfirmation: string;
    31|  requestedBy: string;
