    37|  operation: 'DELETE' | 'TRUNCATE' | 'DROP';
    38|  tables: string[];
    39|  reason: string;
    40|  requestedBy: string;
    41|  targetRecordId: string | number | null;
    42|  firstApprovalAt: string;
    43|  firstApprover: string;
    44|  secondApprovalAt: string | null;
    45|  secondApprover: string | null;
    46|  status: 'pending_second_approval' | 'approved' | 'rejected' | 'expired';
