   113|export async function createDestructiveApproval(input: DestructiveApprovalRequest): Promise<CreateApprovalResult> {
   114|  if (input.typedConfirmation !== input.operation) {
   115|    return { ok: false, approval: null, error: `Typed confirmation must exactly match "${input.operation}". Received "${input.typedConfirmation}".` };
   116|  }
   117|  if (!input.reason.trim()) {
   118|    return { ok: false, approval: null, error: 'A written reason is required for every destructive operation.' };
   119|  }
   120|  if (input.tables.length === 0) {
   121|    return { ok: false, approval: null, error: 'At least one affected table must be specified.' };
   122|  }
   123|
   124|  const firstApprover = input.requestedBy;
   125|  const now = new Date().toISOString();
   126|  const record: DestructiveApprovalRecord = {
   127|    approvalId: makeApprovalId(),
   128|    operation: input.operation,
   129|    tables: input.tables,
   130|    reason: input.reason.slice(0, 2000),
   131|    requestedBy: input.requestedBy,
   132|    targetRecordId: input.targetRecordId ?? null,
   133|    firstApprovalAt: now,
   134|    firstApprover,
   135|    secondApprovalAt: null,
   136|    secondApprover: null,
   137|    status: 'pending_second_approval',
   138|    typedConfirmation: input.typedConfirmation,
   139|    hash: hashApproval(input, firstApprover),
   140|    marker: IVX_TWO_PERSON_MARKER,
   141|  };
   142|
   143|  await appendApproval(record);
   144|  return { ok: true, approval: record, error: null };
