   152|
   153|/**
   154| * Step 2 — second approver confirms. The operation may only proceed once
   155| * status becomes 'approved'.
   156| */
   157|export async function confirmDestructiveApproval(approvalId: string, secondApprover: string): Promise<ConfirmApprovalResult> {
   158|  const records = await readApprovalRecords(500);
   159|  const idx = records.findIndex((r) => r.approvalId === approvalId);
   160|  if (idx === -1) {
   161|    return { ok: false, approval: null, error: 'Approval request not found.' };
   162|  }
   163|  const record = records[idx];
   164|  if (record.status === 'approved') {
   165|    return { ok: false, approval: record, error: 'Approval already confirmed.' };
   166|  }
   167|  if (record.status === 'rejected' || record.status === 'expired') {
   168|    return { ok: false, approval: record, error: `Approval is ${record.status} and cannot be confirmed.` };
   169|  }
   170|  if (record.firstApprover === secondApprover) {
   171|    return { ok: false, approval: record, error: 'Second approver must be a different identity from the first approver.' };
   172|  }
   173|
   174|  const now = new Date().toISOString();
   175|  const updated: DestructiveApprovalRecord = {
   176|    ...record,
   177|    secondApprovalAt: now,
   178|    secondApprover,
   179|    status: 'approved',
   180|  };
   181|  await appendApproval(updated);
   182|  return { ok: true, approval: updated, error: null };
   183|}
   184|
   185|/**
   186| * Reject a pending approval.
   187| */
   188|export async function rejectDestructiveApproval(approvalId: string, rejectedBy: string): Promise<ConfirmApprovalResult> {
   189|  const records = await readApprovalRecords(500);
   190|  const record = records.find((r) => r.approvalId === approvalId);
   191|  if (!record) return { ok: false, approval: null, error: 'Approval request not found.' };
   192|  if (record.status !== 'pending_second_approval') {
   193|    return { ok: false, approval: record, error: `Approval is already ${record.status}.` };
   194|  }
   195|  const updated: DestructiveApprovalRecord = { ...record, status: 'rejected', secondApprover: rejectedBy };
