    75|async function dirSize(dir: string): Promise<number> {
    76|  try {
    77|    const entries = await fs.readdir(dir, { withFileTypes: true });
    78|    let total = 0;
    79|    for (const ent of entries) {
    80|      const full = path.join(dir, ent.name);
    81|      if (ent.isDirectory()) {
    82|        total += await dirSize(full);
    83|      } else if (ent.isFile()) {
    84|        const stat = await fs.stat(full);
    85|        total += stat.size;
    86|      }
    87|    }
    88|    return total;
    89|  } catch {
    90|    return 0;
    91|  }
