    94|async function countTable(baseUrl: string, key: string, table: string): Promise<TableCount> {
    95|  try {
    96|    const res = await fetch(`${baseUrl}/rest/v1/${table}?select=id`, {
    97|      method: 'GET',
    98|      headers: { apikey: key, Authorization: `Bearer ${key}`, Range: '0-0', Prefer: 'count=exact' },
    99|    });
   100|    if (res.status === 404) return { table, count: null, exists: false, error: 'TABLE_NOT_FOUND' };
   101|    if (!res.ok) return { table, count: null, exists: true, error: `HTTP_${res.status}` };
   102|    const cr = res.headers.get('content-range');
   103|    const count = cr ? parseInt(cr.split('/').pop() || '*', 10) : null;
   104|    return { table, count: Number.isFinite(count) ? count : null, exists: true, error: null };
   105|  } catch (err) {
   106|    return { table, count: null, exists: false, error: err instanceof Error ? err.message : 'network_error' };
   107|  }
