   113|export async function generateDailyReport(): Promise<DailyReport> {
   114|  const generatedAt = new Date().toISOString();
   115|  const date = generatedAt.slice(0, 10);
   116|
   117|  const supa = resolveSupabase();
   118|  const state = await getDataVaultState();
   119|  const snapshots = await listSnapshots(1000);
   120|  const manifest = await readManifest(200);
   121|  const destructiveAudit = await readDestructiveOpAudit(200);
   122|  const approvals = await readApprovalRecords(200);
   123|  const dataLossAlert = await detectDataLoss();
   124|
   125|  // Row counts
   126|  const rowCounts: TableCount[] = [];
   127|  if (supa.missing.length === 0) {
   128|    for (const table of CRITICAL_TABLES) {
   129|      rowCounts.push(await countTable(supa.url, supa.key, table));
   130|    }
   131|  } else {
   132|    for (const table of CRITICAL_TABLES) {
   133|      rowCounts.push({ table, count: null, exists: false, error: `not_configured: ${supa.missing.join(', ')}` });
   134|    }
   135|  }
   136|
   137|  // Soft-deleted counts (best-effort, may fail if tables lack deleted_at)
   138|  const softDeletedCounts: { table: string; count: number; error: string | null }[] = [];
   139|  for (const table of ['members', 'investors', 'buyers', 'waitlist']) {
   140|    try {
   141|      const result = await listSoftDeleted(table, 1000);
   142|      softDeletedCounts.push({ table, count: result.count, error: result.error });
   143|    } catch (err) {
   144|      softDeletedCounts.push({ table, count: 0, error: err instanceof Error ? err.message : 'error' });
   145|    }
   146|  }
   147|
   148|  // Vault size on disk
   149|  const vaultDir = path.resolve(process.cwd(), 'logs', 'audit', 'data-vault');
   150|  const vaultSizeBytes = await dirSize(vaultDir);
   151|
   152|  // Restored records from manifest (count snapshots that restored data)
   153|  const restoredRecords = manifest.length;
   154|
   155|  const pendingApprovals = approvals.filter((a) => a.status === 'pending_second_approval').length;
   156|  const destructiveOpsLogged = destructiveAudit.length;
   157|
   158|  const pitr = await checkPitrStatus(snapshots.length, state.lastSnapshotAt);
   159|
   160|  // Risk assessment
   161|  const riskReasons: string[] = [];
   162|  if (state.totalSnapshots === 0) riskReasons.push('No file-vault snapshots exist yet.');
   163|  if (!pitr.supabaseReachable) riskReasons.push('Supabase is not reachable.');
   164|  if (dataLossAlert.detected) riskReasons.push(`Data loss detected on ${dataLossAlert.tablesAffected.length} table(s).`);
   165|  if (destructiveOpsLogged > 0 && destructiveAudit.filter((d) => !d.allowed).length > 5) riskReasons.push('Multiple destructive ops were blocked recently — investigate autonomous cleanup attempts.');
   166|  if (vaultSizeBytes === 0) riskReasons.push('Vault directory is empty — no backups on disk.');
   167|
   168|  const recoveryRisk: 'low' | 'medium' | 'high' = riskReasons.length >= 3 ? 'high' : riskReasons.length >= 1 ? 'medium' : 'low';
   169|
   170|  const recommendation = recoveryRisk === 'low'
   171|    ? 'All recovery systems healthy. Continue daily snapshots.'
   172|    : recoveryRisk === 'medium'
   173|    ? `Address: ${riskReasons.join('; ')}. Run a manual snapshot and confirm PITR in the Supabase Dashboard.`
   174|    : `CRITICAL: ${riskReasons.join('; ')}. Immediate action required — run a snapshot now, enable Supabase PITR, and run the recovery drill.`;
   175|
   176|  const report: DailyReport = {
   177|    marker: IVX_REPORT_MARKER,
   178|    generatedAt,
   179|    date,
   180|    backupStatus: {
   181|      fileVaultEnabled: state.config.enabled,
   182|      fileVaultLastSnapshotAt: state.lastSnapshotAt,
   183|      fileVaultLastSnapshotId: state.lastSnapshotId,
   184|      fileVaultTotalSnapshots: state.totalSnapshots,
   185|      supabaseReachable: pitr.supabaseReachable,
   186|    },
   187|    rowCounts,
   188|    softDeletedCounts,
   189|    vaultSizeBytes,
   190|    vaultSizeNote: vaultSizeBytes === 0 ? 'Vault directory is empty.' : `${(vaultSizeBytes / 1024).toFixed(1)} KB on disk`,
   191|    restoredRecords,
   192|    destructiveOpsLogged,
   193|    pendingApprovals,
   194|    pitr,
   195|    dataLossAlert,
   196|    recoveryRisk,
   197|    riskReasons,
   198|    recommendation,
   199|  };
   200|
   201|  // Persist to disk
   202|  try {
   203|    await fs.mkdir(REPORTS_DIR, { recursive: true });
   204|    const filename = `report-${date}-${Date.now()}.json`;
   205|    await fs.writeFile(path.join(REPORTS_DIR, filename), JSON.stringify(report, null, 2), 'utf8');
   206|  } catch {
   207|    // never fail the report because of persistence
   208|  }
   209|
   210|  return report;
   211|}
