   216|export async function listDailyReports(limit: number = 10): Promise<{ filename: string; generatedAt: string; date: string; recoveryRisk: string }[]> {
   217|  try {
   218|    const files = await fs.readdir(REPORTS_DIR);
   219|    const reports: { filename: string; generatedAt: string; date: string; recoveryRisk: string }[] = [];
   220|    for (const file of files.slice(-limit * 2)) {
   221|      if (!file.endsWith('.json')) continue;
   222|      try {
   223|        const raw = JSON.parse(await fs.readFile(path.join(REPORTS_DIR, file), 'utf8')) as DailyReport;
   224|        reports.push({ filename: file, generatedAt: raw.generatedAt, date: raw.date, recoveryRisk: raw.recoveryRisk });
   225|      } catch { /* skip corrupt */ }
   226|    }
   227|    return reports.sort((a, b) => (a.generatedAt < b.generatedAt ? 1 : -1)).slice(0, limit);
