   134|/**
   135| * Extract table names from a destructive SQL string. Best-effort regex
   136| * extraction — not a full SQL parser. Returns lowercased table names.
   137| * Pure function — deterministic.
   138| */
   139|export function extractTableNames(sql: string): string[] {
   140|  if (!sql || typeof sql !== 'string') return [];
   141|  const tables = new Set<string>();
   142|
   143|  // DELETE FROM <table>
   144|  let m: RegExpExecArray | null;
   145|  const deleteRe = /\bDELETE\s+FROM\s+(?:public\.)?([a-z_][a-z0-9_]*)/gi;
   146|  while ((m = deleteRe.exec(sql)) !== null) tables.add(m[1].toLowerCase());
   147|
   148|  // TRUNCATE [TABLE] <table>[, <table2>...]
   149|  const truncateRe = /\bTRUNCATE\s+(?:TABLE\s+)?(?:public\.)?([a-z_][a-z0-9_,\s.]*)/gi;
   150|  while ((m = truncateRe.exec(sql)) !== null) {
   151|    for (const part of m[1].split(',')) {
   152|      const name = part.trim().replace(/^public\./, '').toLowerCase();
   153|      if (name) tables.add(name);
   154|    }
   155|  }
   156|
   157|  // DROP TABLE <table>
   158|  const dropRe = /\bDROP\s+TABLE\s+(?:IF\s+EXISTS\s+)?(?:public\.)?([a-z_][a-z0-9_]*)/gi;
   159|  while ((m = dropRe.exec(sql)) !== null) tables.add(m[1].toLowerCase());
   160|
   161|  return Array.from(tables);
