   201|    }
   202|  }
   203|
   204|  const allowed = blocker === null;
   205|
   206|  const auditEntry: DestructiveOpAuditEntry = {
   207|    timestamp,
   208|    operation: request.operation.slice(0, 2000),
   209|    tables,
   210|    isAutonomous: request.isAutonomous,
   211|    ownerApproved: request.ownerApproved,
   212|    ownerReason: request.ownerReason,
   213|    emergency: request.emergency,
   214|    allowed,
   215|    blocker,
   216|    snapshotId: snapshotTaken?.snapshotId ?? null,
   217|    marker: IVX_DATA_LOSS_GUARD_MARKER,
